import torch
from torch.utils.data import Dataset
import pandas as pd
from datasets import load_dataset
from transformers import AutoTokenizer

class RlhfCrowdDataset(Dataset):
    def __init__(self, votes_csv, truth_csv, max_length=128):
        # Load the CSVs generated by simulator.py
        self.votes_df = pd.read_csv(votes_csv)
        self.truth_df = pd.read_csv(truth_csv)
        
        # Load the exact same Anthropic dataset
        print("Loading HF dataset for raw text...")
        self.hf_dataset = load_dataset("Anthropic/hh-rlhf", split=f"train[:{len(self.truth_df)}]")
        
        # Initialize Tokenizer
        self.tokenizer = AutoTokenizer.from_pretrained("gpt2")
        self.tokenizer.pad_token = self.tokenizer.eos_token
        self.max_length = max_length

    def __len__(self):
        return len(self.votes_df)

    def __getitem__(self, idx):
        # Get the vote record
        vote_row = self.votes_df.iloc[idx]
        prompt_id = int(vote_row['prompt_id'])
        annotator_id = int(vote_row['annotator_id'])
        vote = float(vote_row['vote'])

        # Look up the text and ground truth
        hf_row = self.hf_dataset[prompt_id]
        truth_is_A = self.truth_df[self.truth_df['prompt_id'] == prompt_id]['truth_is_A'].values[0]

        # Reconstruct Response A and B exactly as the simulator saw them
        text_A = hf_row['chosen'] if truth_is_A else hf_row['rejected']
        text_B = hf_row['rejected'] if truth_is_A else hf_row['chosen']

        # Tokenize (convert words to integer IDs)
        tokens_A = self.tokenizer(text_A, truncation=True, max_length=self.max_length, padding="max_length", return_tensors="pt")
        tokens_B = self.tokenizer(text_B, truncation=True, max_length=self.max_length, padding="max_length", return_tensors="pt")

        return {
            "prompt_id": prompt_id,
            "annotator_id": annotator_id,
            "vote": vote,
            "input_ids_A": tokens_A['input_ids'].squeeze(0),
            "input_ids_B": tokens_B['input_ids'].squeeze(0)
        }